---@class UITigerDraw
local UITigerDraw = LxClass("UITigerDraw",nil)

local YXUICircleScroll = CS.YXUICircleScroll
UITigerDraw.Normal = YXUICircleScroll.MoveType.Normal
UITigerDraw.Auto = YXUICircleScroll.MoveType.Auto

--- 水平
UITigerDraw.Horizontal = 1

--- 垂直
UITigerDraw.Vertical = 2


function UITigerDraw:UITigerDraw()
    ---@type LWnd
    self._wndClass = nil

    --- trans:列表节点,direType:方向
    self._tigerListInfos = {}

    ---@type table<string,UIItemList>
    self._saveListMap = {}

    self._saveInfoDatas = {}
end

---@return LWnd
function UITigerDraw:GetWndClass()
    return self._wndClass
end

---@param wndClass LWnd
function UITigerDraw:SetTigerListInfos(wndClass,data)
    self._wndClass = wndClass

    for i,v in ipairs(data) do
        self:SetTigerInfo(v)
    end
end

--- info 数据：
---# trans:列表节点
---# dataList:列表数据
---# autoMove:是否自动移动
---# speed:移动速度
---# isMoveState:是否开始移动
---# isLeft:是否从左到右移动
function UITigerDraw:SetTigerInfo(info)
    local wndClass = self:GetWndClass()
    if not wndClass then return end

    local trans = info.trans
    local key = trans:GetInstanceID()
    local uiItemList = wndClass:GetUIScroll(key)
    self._saveListMap[key] = uiItemList
    uiItemList:InitListData({
        root = trans,
        dataList = info.dataList,
        setFunc = function(...) self:OnDrawTigerCell(...)  end,
        type = UIItemList.CIRCLE,
        centerPos = 0
    })

    ---@type UIListCircle
    local uiList = uiItemList:GetList()
    local isAutoMove = info.autoMove
    local moveType = isAutoMove and UITigerDraw.Auto or UITigerDraw.Normal
    local speed = info.speed or 500
    uiList:SetMoveType(moveType,speed)
    local isMoveState = info.isMoveState or false
    local isLeft = info.isLeft or false
    uiList:StartMove(isMoveState,isLeft)

    self._saveInfoDatas[key] = {
        trans = trans,
        uiItemList = uiItemList,
        dataList = info.dataList,
        moveType = moveType,
        constSpeed = speed,
        speed = speed,
        isMoveState = isMoveState,
        isLeft = isLeft,
    }
end

function UITigerDraw:OnDrawTigerCell(list,item, itemdata, itempos)
    local wndClass = self:GetWndClass()
    if not wndClass then return end

    local Icon = wndClass:FindWndTrans(item,"Icon")
    wndClass:SetWndEasyImage(Icon,itemdata.imgPath,function()
        CS.ShowObject(Icon,true)
    end,true)
end

function UITigerDraw:GetUIScrollByTrans(trans)
    local wndClass = self:GetWndClass()
    if not wndClass then return end
    local key = trans:GetInstanceID()
    return self._saveListMap[key]
end

function UITigerDraw:SetUIScrollSpeedByTrans(trans,speed)
    local uiScrollList = self:GetUIScrollByTrans(trans)
    if not uiScrollList then return end

    local key = trans:GetInstanceID()
    local info = self._saveInfoDatas[key]
    if not info then return end

    local uiList = uiScrollList:GetList()
    uiList:SetMoveType(info.moveType,speed)
end

function UITigerDraw:SetAllUIScrollSpeed(speed)
    local wndClass = self:GetWndClass()
    if not wndClass then return end

    for k,v in pairs(self._saveInfoDatas) do
        self:SetUIScrollSpeedByTrans(v.trans,speed)
    end
end

function UITigerDraw:SetUIScrollStartMoveByTrans(trans,state)
    local uiScrollList = self:GetUIScrollByTrans(trans)
    if not uiScrollList then return end

    local key = trans:GetInstanceID()
    local info = self._saveInfoDatas[key]
    if not info then return end

    local uiList = uiScrollList:GetList()
    local isLeft = info.isLeft or false
    uiList:StartMove(state,isLeft)
end

function UITigerDraw:SetAllUIScrollMoveState(state)
    local wndClass = self:GetWndClass()
    if not wndClass then return end

    for k,v in pairs(self._saveInfoDatas) do
        self:SetUIScrollStartMoveByTrans(v.trans,state)
    end
end

function UITigerDraw:RefreshAllUIScrollList(infos)
    if not infos then return end

    local wndClass = self:GetWndClass()
    if not wndClass then return end


    for i,v in ipairs(infos) do
        local trans = v.trans
        local key = trans:GetInstanceID()
        local info = self._saveInfoDatas[key]
        if info then
            info.uiItemList:RefreshList(v.dataList)
        end
    end
end

function UITigerDraw:Destroy()
    if self:IsDestroy() then return end
    table.removeall(self)
    self._isDestroy = true
end

function UITigerDraw:IsDestroy()
    return self._isDestroy
end

return UITigerDraw